// Script Continued Below
var OrganizationalHierarchyACLs = Class.create();
OrganizationalHierarchyACLs.prototype = {
    initialize: function() {
		this.userInfo = new UserInfoScripts();
	},

	// STRY0138377
	canReadOrgContact: function (grContact){
		var userCanRead = false;
		var ouId = grContact.getValue("u_contact_ou");
		userCanRead = new task_privacy().userCanAccessOU(ouId);
		return userCanRead;
	},

	// STRY0138377
	canReadMember: function (grMember){
		var userCanRead = false;
		var ouId = grMember.getValue("discover_office_hierarchy");
		userCanRead = new task_privacy().userCanAccessOU(ouId);
		return userCanRead;
	},

	// STRY0138377
	canRead: function (grOU){
		var userCanRead = false;
		// DFCT0012030 -DFCT0012031
		if(grOU.isNewRecord()){
			userCanRead = true;
		} else {

			var ouId = grOU.getUniqueValue();

			var isExternal = grOU.getValue("u_external_flag") == true;
			if(isExternal){
				userCanRead = true;
			} else{
				userCanRead = new task_privacy().userCanAccessOU(ouId);			
			}
		}

		return userCanRead;
	},

	// STRY0138378
	userCanWriteOUPrivacy: function(grOU){
		var answer = false;
		// DFCT0011804
		var isTopOU = grOU.getDisplayValue("parent") == '' || grOU.getDisplayValue("parent") == null;
		// DFCT0011930
		var isUserOrganizationalAdmin = false;
		var ouId;
		var userHasOrganizationalAdminRole = this.userInfo.UserHasRole('x_153465_discovert.tasker_organizational_admin');
		var userHasTAARole = this.userInfo.UserHasRole('x_153465_discovert.tasker_application_admin');
		// isExternal was moved to forms.  when doing the check in acl, the field would not become editable on change
		if(!isTopOU ){
			answer = false;
		} else {
			// DFCT0011930
			if(grOU.isNewRecord()){
				if(userHasOrganizationalAdminRole || userHasTAARole){
					answer = true;
				}
			} else {
				ouId = grOU.getUniqueValue();
				isUserOrganizationalAdmin = this.userInfo.userIsOrgAdminForOU(ouId);
				if(isUserOrganizationalAdmin){
					answer = true;
				}
			}
		}
		return answer;
	},

	// STRY0138378
	userCanWriteOUisExternal: function(grOU){
		var answer = false;
		var isTopOU = grOU.getDisplayValue("parent") == '' || grOU.getDisplayValue("parent") == null;
		// DFCT0011930
		var isUserOrganizationalAdmin = false;
		var ouId;
		var userHasOrganizationalAdminRole = this.userInfo.UserHasRole('x_153465_discovert.tasker_organizational_admin');
		var userHasTAARole = this.userInfo.UserHasRole('x_153465_discovert.tasker_application_admin');

		// If the OU is external check was moved to forms. when doing hte check in acl, the field would not become editable on change
		if(!isTopOU){
			answer = false;
		} else {
			// DFCT0011930
			if(grOU.isNewRecord()){
				if(userHasOrganizationalAdminRole || userHasTAARole){
					answer = true;
				}
			} else {
				ouId = grOU.getUniqueValue();
				isUserOrganizationalAdmin = this.userInfo.userIsOrgAdminForOU(ouId);
				if(isUserOrganizationalAdmin){
					answer = true;
				}
			}
		}
		return answer;
	},

	type: 'OrganizationalHierarchyACLs'
};
